//! Hope Jar E6 — the 51,840-key entropy battery.
//!
//! The smallest exceptional tier (lowest capacity, fastest cold start).
//!
//! Capacity = |W(E_6)| = 51,840
//!          = h(E_6) × |Φ(E_6)| × carriers_per_slot
//!          = 12 × 72 × 60.
//!
//! Structure mirrors `hope_jar_e7.rs` and `hope_jar_e8.rs` with reduced dimensions.
//!
//! Lean SSOT: `Gnosis.HopeJarE6.e6_jar_capacity_eq_decomposition`

use crate::hope_jar::BoxState;

/// |W(E_6)| — the full key capacity. Latent, never materialised.
pub const E6_WEYL_ORDER: u64 = 51_840;
/// E_6 Coxeter number — the aeon phase count.
pub const COXETER_PHASES: usize = 12;
/// E_6 root count — the discharge lane count.
pub const ROOT_LANES: usize = 72;
/// Carriers per (phase, lane) slot: 51840 / (12·72).
pub const CARRIERS_PER_SLOT: usize = 60;
/// Seeds needed to seal the jar.
pub const CHARGE_SEEDS: usize = 170;

const FIBONACCI_HASH: u64 = 11_400_714_819_323_198_485;

/// The E_6 Hope Jar: sealed latent 51,840-key entropy battery.
#[derive(Clone, Debug)]
pub struct HopeJarE6 {
    seeds: Vec<u64>,
    lane_codes: Vec<u64>,
    state: BoxState,
    charge_cost_us: u64,
    total_discharges: u64,
}

/// Generate deterministic, unique lane codes for the 72 E_6 roots.
fn lane_codes() -> Vec<u64> {
    (0..ROOT_LANES)
        .map(|i| {
            (i as u64)
                .wrapping_mul(FIBONACCI_HASH)
                .wrapping_add(0xfeedbeef_u64)
        })
        .collect()
}

impl HopeJarE6 {
    pub fn new() -> Self {
        Self {
            seeds: Vec::new(),
            lane_codes: lane_codes(),
            state: BoxState::Empty,
            charge_cost_us: 0,
            total_discharges: 0,
        }
    }

    pub fn state(&self) -> BoxState {
        self.state
    }

    pub fn seeds_loaded(&self) -> usize {
        self.seeds.len()
    }

    pub fn total_discharges(&self) -> u64 {
        self.total_discharges
    }

    pub fn is_sealed(&self) -> bool {
        self.state == BoxState::Sealed
    }

    /// Full key capacity (latent) = |W(E_6)|.
    pub fn capacity(&self) -> u64 {
        E6_WEYL_ORDER
    }

    /// Charge from standing-wave seeds.
    pub fn charge_from_seeds(&mut self, seeds: &[u64], analysis_time_us: u64) {
        if self.state == BoxState::Sealed {
            return;
        }
        self.state = BoxState::Charging;
        self.charge_cost_us += analysis_time_us;
        for &seed in seeds {
            if self.seeds.len() >= CHARGE_SEEDS {
                break;
            }
            self.seeds.push(seed);
        }
        if self.seeds.len() >= CHARGE_SEEDS {
            self.state = BoxState::Sealed;
        }
    }

    /// Deterministic per-slot seed.
    fn slot_seed(&self, phase: usize, lane: usize) -> u64 {
        let base = if self.seeds.is_empty() {
            FIBONACCI_HASH
        } else {
            self.seeds[(phase * ROOT_LANES + lane) % self.seeds.len()]
        };
        base.wrapping_mul(FIBONACCI_HASH)
            .wrapping_add(self.lane_codes[lane])
            .wrapping_mul(FIBONACCI_HASH)
            .wrapping_add(phase as u64)
    }

    /// Regenerate the 60 carriers of one (phase, lane) slot.
    pub fn discharge_iter(&self, phase: u8, lane: u8) -> impl Iterator<Item = u64> + '_ {
        let sealed = self.state == BoxState::Sealed;
        let p = (phase as usize) % COXETER_PHASES;
        let l = (lane as usize) % ROOT_LANES;
        let base = if sealed { self.slot_seed(p, l) } else { 0 };
        let count = if sealed { CARRIERS_PER_SLOT } else { 0 };
        (0..count).map(move |k| {
            base.wrapping_mul(FIBONACCI_HASH)
                .wrapping_add(k as u64)
                .wrapping_mul(FIBONACCI_HASH)
        })
    }

    /// Materialise one slot's carriers (convenience).
    pub fn discharge(&mut self, phase: u8, lane: u8) -> Vec<u64> {
        if self.state != BoxState::Sealed {
            return Vec::new();
        }
        self.total_discharges += 1;
        self.discharge_iter(phase, lane).collect()
    }

    /// Predict a single key for a shape hash (O(1) point query).
    pub fn predict(&self, shape_hash: u64) -> u64 {
        if self.state != BoxState::Sealed {
            return 0;
        }
        let phase = (shape_hash % COXETER_PHASES as u64) as usize;
        let lane = ((shape_hash / COXETER_PHASES as u64) % ROOT_LANES as u64) as usize;
        let k =
            (shape_hash / (COXETER_PHASES as u64 * ROOT_LANES as u64)) % CARRIERS_PER_SLOT as u64;
        self.slot_seed(phase, lane)
            .wrapping_mul(FIBONACCI_HASH)
            .wrapping_add(k)
            .wrapping_mul(FIBONACCI_HASH)
    }

    pub fn telemetry(&self) -> HopeJarE6Telemetry {
        HopeJarE6Telemetry {
            state: self.state,
            seeds_loaded: self.seeds.len(),
            capacity: E6_WEYL_ORDER,
            phases: COXETER_PHASES,
            lanes: ROOT_LANES,
            carriers_per_slot: CARRIERS_PER_SLOT,
            charge_cost_us: self.charge_cost_us,
            total_discharges: self.total_discharges,
        }
    }
}

impl Default for HopeJarE6 {
    fn default() -> Self {
        Self::new()
    }
}

#[derive(Clone, Debug)]
pub struct HopeJarE6Telemetry {
    pub state: BoxState,
    pub seeds_loaded: usize,
    pub capacity: u64,
    pub phases: usize,
    pub lanes: usize,
    pub carriers_per_slot: usize,
    pub charge_cost_us: u64,
    pub total_discharges: u64,
}

impl std::fmt::Display for HopeJarE6Telemetry {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(
            f,
            "HopeJarE6[{:?}] seeds={} cap={} ({}×{}×{}) cost={}us discharges={}",
            self.state,
            self.seeds_loaded,
            self.capacity,
            self.phases,
            self.lanes,
            self.carriers_per_slot,
            self.charge_cost_us,
            self.total_discharges,
        )
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn rain_seeds() -> Vec<u64> {
        (0..CHARGE_SEEDS as u64)
            .map(|i| i.wrapping_mul(2654435761).wrapping_add(1))
            .collect()
    }

    #[test]
    fn test_e6_capacity_factorization() {
        assert_eq!(
            COXETER_PHASES * ROOT_LANES * CARRIERS_PER_SLOT,
            E6_WEYL_ORDER as usize
        );
    }

    #[test]
    fn test_e6_jar_charge_and_seal() {
        let mut jar = HopeJarE6::new();
        assert_eq!(jar.state(), BoxState::Empty);
        let seeds = rain_seeds();
        jar.charge_from_seeds(&seeds, 1000);
        assert_eq!(jar.state(), BoxState::Sealed);
        assert!(jar.is_sealed());
        assert_eq!(jar.seeds_loaded(), CHARGE_SEEDS);
    }

    #[test]
    fn test_e6_jar_predict() {
        let mut jar = HopeJarE6::new();
        let seeds = rain_seeds();
        jar.charge_from_seeds(&seeds, 1000);
        let key1 = jar.predict(12345);
        let key2 = jar.predict(12345);
        assert_eq!(key1, key2); // deterministic
        assert_ne!(key1, 0);
    }

    #[test]
    fn test_e6_jar_discharge() {
        let mut jar = HopeJarE6::new();
        let seeds = rain_seeds();
        jar.charge_from_seeds(&seeds, 1000);
        let slot = jar.discharge(0, 0);
        assert_eq!(slot.len(), CARRIERS_PER_SLOT);
        assert!(jar.total_discharges() >= 1);
    }
}
